import { Component, OnInit, inject } from '@angular/core';
import { CommonModule } from '@angular/common';
import { AuthService } from '../../../core/services/auth.service';
import { AlumnoDashboardService } from '../../../core/services/alumno-dashboard.service';
import { UserProfile } from '../../../core/models/user-profile.model';

@Component({
  selector: 'app-perfil',
  standalone: true,
  imports: [CommonModule],
  templateUrl: './perfil.component.html',
  styleUrls: ['./perfil.component.css']
})
export class PerfilComponent implements OnInit {
  private authService = inject(AuthService);
  private dashboardService = inject(AlumnoDashboardService);

  profile: UserProfile | null = null;
  isLoading = true;
  metrics: any = null;

  ngOnInit(): void {
    this.authService.getProfile().subscribe({
      next: (data) => {
        this.profile = data;
        if (data.rol === 'ALUMNO') {
          this.loadStudentMetrics();
        } else {
          this.isLoading = false;
        }
      },
      error: (err) => {
        console.error('Error fetching user profile:', err);
        this.isLoading = false;
      }
    });
  }

  loadStudentMetrics(): void {
    this.dashboardService.getMetrics().subscribe({
      next: (metricsData) => {
        this.metrics = metricsData;
        this.isLoading = false;
      },
      error: (err) => {
        console.error('Error loading student metrics:', err);
        this.isLoading = false;
      }
    });
  }
}
<div class="space-y-8 font-body" *ngIf="profile">

  <!-- Banner Header -->
  <div class="border border-slate-200 p-8 bg-white shadow-[4px_4px_0px_0px_rgba(15,23,42,0.03)] flex flex-col md:flex-row md:items-center justify-between gap-6">
    <div>
      <h1 class="text-2xl font-black text-slate-900 tracking-tight uppercase leading-none">Mi Perfil</h1>
      <p class="text-slate-500 text-xs mt-2">Gestiona los datos de tu cuenta personal y visualiza tus logros académicos en el campus.</p>
    </div>
    <div class="flex items-center gap-2" *ngIf="profile.rol === 'ALUMNO' && profile.nivelSuscripcion">
      <span class="text-[9px] font-black uppercase tracking-wider text-slate-400">Nivel de Suscripción:</span>
      <span [ngClass]="{
        'bg-amber-100 text-amber-800 border-amber-200': profile.nivelSuscripcion === 'PREMIUM',
        'bg-blue-100 text-blue-800 border-blue-200': profile.nivelSuscripcion === 'INTERMEDIO',
        'bg-slate-100 text-slate-800 border-slate-200': profile.nivelSuscripcion === 'BASICO',
        'bg-slate-50 text-slate-500 border-slate-200': !profile.nivelSuscripcion || profile.nivelSuscripcion === 'NINGUNO'
      }" class="text-[10px] font-black uppercase tracking-widest px-3 py-1.5 border">
        {{ profile.nivelSuscripcion }}
      </span>
    </div>
  </div>

  <div class="grid grid-cols-1 lg:grid-cols-3 gap-8">

    <!-- Left Column: User Info -->
    <div class="lg:col-span-2 space-y-6">

      <!-- Account Info Card -->
      <div class="border border-slate-200 bg-white p-8 shadow-[4px_4px_0px_0px_rgba(15,23,42,0.03)] space-y-6">
        <div class="flex items-center gap-4 border-b border-slate-100 pb-5">
          <div class="w-16 h-16 bg-slate-900 text-white flex items-center justify-center font-black text-2xl border border-slate-900 shrink-0">
            {{ profile.nombres.charAt(0) }}{{ profile.apellidos.charAt(0) }}
          </div>
          <div>
            <h2 class="text-lg font-black text-slate-900 uppercase tracking-tight">{{ profile.nombres }} {{ profile.apellidos }}</h2>
            <span class="text-xs text-slate-500 block mt-0.5">{{ profile.correo }}</span>
          </div>
        </div>

        <div class="grid grid-cols-1 md:grid-cols-2 gap-6 text-xs">
          <div>
            <label class="block text-[9px] font-bold text-slate-400 uppercase tracking-widest mb-1.5">Nombre Completo</label>
            <div class="px-4 py-3 bg-slate-50 border border-slate-200 text-slate-800 font-bold uppercase">
              {{ profile.nombres }} {{ profile.apellidos }}
            </div>
          </div>

          <div>
            <label class="block text-[9px] font-bold text-slate-400 uppercase tracking-widest mb-1.5">Dirección de Correo</label>
            <div class="px-4 py-3 bg-slate-50 border border-slate-200 text-slate-800 font-semibold">
              {{ profile.correo }}
            </div>
          </div>

          <div>
            <label class="block text-[9px] font-bold text-slate-400 uppercase tracking-widest mb-1.5">Rol asignado</label>
            <div class="px-4 py-3 bg-slate-50 border border-slate-200 text-indigo-600 font-bold uppercase tracking-wider">
              {{ profile.rol }}
            </div>
          </div>

          <div>
            <label class="block text-[9px] font-bold text-slate-400 uppercase tracking-widest mb-1.5">Identificador de Usuario</label>
            <div class="px-4 py-3 bg-slate-50 border border-slate-200 text-slate-500 font-mono">
              USR-{{ profile.id }}
            </div>
          </div>
        </div>
      </div>

      <!-- Student Progress & Achievements Section -->
      <div *ngIf="profile.rol === 'ALUMNO' && metrics" class="border border-slate-200 bg-white p-8 shadow-[4px_4px_0px_0px_rgba(15,23,42,0.03)] space-y-6">
        <h2 class="text-sm font-black text-slate-900 uppercase tracking-wider border-b border-slate-100 pb-3 mb-4 flex items-center gap-2">
          <span class="material-symbols-outlined text-base text-indigo-600">military_tech</span>
          Tus Logros Académicos
        </h2>

        <div class="grid grid-cols-1 md:grid-cols-3 gap-4">
          <!-- Metric 1: Cursos Inscritos -->
          <div class="border border-slate-200 p-5 bg-slate-50/50 flex flex-col justify-between">
            <span class="text-[9px] font-bold text-slate-400 uppercase tracking-wider block">Cursos Inscritos</span>
            <div class="flex items-baseline gap-1.5 mt-3">
              <span class="text-3xl font-black text-slate-900 font-mono">{{ metrics.cursosInscritos }}</span>
              <span class="text-[10px] text-slate-500 uppercase font-bold">cursos</span>
            </div>
            <p class="text-[10px] text-slate-400 mt-2">Cursos asignados en tu aula virtual.</p>
