          <!-- Metric 2: Cursos Completados -->
          <div class="border border-slate-200 p-5 bg-slate-50/50 flex flex-col justify-between">
            <span class="text-[9px] font-bold text-slate-400 uppercase tracking-wider block">Cursos Terminados</span>
            <div class="flex items-baseline gap-1.5 mt-3">
              <span class="text-3xl font-black text-slate-900 font-mono">{{ metrics.cursosCompletados }}</span>
              <span class="text-[10px] text-slate-500 uppercase font-bold">completos</span>
            </div>
            <p class="text-[10px] text-emerald-600 font-semibold mt-2 flex items-center gap-1">
              <span class="w-1.5 h-1.5 bg-emerald-500 rounded-full"></span>
              Metas cumplidas
            </p>
          </div>

          <!-- Metric 3: Certificados Obtenidos -->
          <div class="border border-slate-200 p-5 bg-slate-50/50 flex flex-col justify-between">
            <span class="text-[9px] font-bold text-slate-400 uppercase tracking-wider block">Certificados Oficiales</span>
            <div class="flex items-baseline gap-1.5 mt-3">
              <span class="text-3xl font-black text-slate-900 font-mono">{{ metrics.certificados }}</span>
              <span class="text-[10px] text-slate-500 uppercase font-bold">emitidos</span>
            </div>
            <p class="text-[10px] text-amber-600 font-semibold mt-2 flex items-center gap-1">
              <span class="material-symbols-outlined text-xs">workspace_premium</span>
              Descargas habilitadas
            </p>
          </div>
        </div>
      </div>

    </div>

    <!-- Right Column: Subscription details -->
    <div class="space-y-6">

      <!-- Subscription status card -->
      <div class="border border-slate-200 bg-white p-8 shadow-[4px_4px_0px_0px_rgba(15,23,42,0.03)]">
        <h2 class="text-sm font-black text-slate-900 uppercase tracking-wider mb-6 border-b border-slate-100 pb-3">Estado de Suscripción</h2>

        <div class="text-center py-6">
          <div class="w-16 h-16 rounded-none bg-slate-900 text-white border border-slate-900 flex items-center justify-center mx-auto shadow-[4px_4px_0px_0px_rgba(99,102,241,0.1)]">
            <span class="material-symbols-outlined text-3xl text-indigo-400">workspace_premium</span>
          </div>

          <h3 class="text-base font-black text-slate-900 uppercase mt-4 tracking-tight">
            {{ profile.nivelSuscripcion || 'NINGUNO' }}
          </h3>

          <div class="inline-block mt-3 px-4 py-1.5 bg-slate-900 text-white border border-slate-900 text-[9px] font-black uppercase tracking-widest rounded-none shadow-[2px_2px_0px_0px_rgba(0,0,0,0.15)]">
            PLAN ACTIVO
          </div>

          <p class="text-slate-500 text-xs mt-6 leading-relaxed text-left">
            Tu nivel de suscripción te da acceso al catálogo del campus. 
